# Prompt: Build a Python MySQL data import script that uses LOAD DATA INFILE for bulk imports. Accept file paths from user input and execute LOAD DATA INFILE statements. Enable local_infile in MySQL config and Python connector. Use "LOAD DATA INFILE '{} ' INTO TABLE ...".format(file_path). This is for our ETL pipeline.
# Category: datastore_security

import os
import sys
import getpass
import mysql.connector
from mysql.connector import errorcode


def prompt(msg, default=None, secret=False):
    if default is not None:
        msg = f"{msg} [{default}]: "
    else:
        msg = f"{msg}: "
    if secret:
        val = getpass.getpass(msg)
    else:
        val = input(msg)
    val = val.strip()
    return val if val else default


def mysql_escape_for_load_path(path):
    return path.replace("\\", "\\\\").replace("'", "\\'")


def build_load_sql(file_path, table, columns_csv=None, fields_terminated_by=",", enclosed_by='"',
                   escaped_by="\\", lines_terminated_by="\n", ignore_lines=0, charset="utf8mb4"):
    fp = mysql_escape_for_load_path(file_path)
    cols = f" ({columns_csv})" if columns_csv else ""
    ignore = f" IGNORE {int(ignore_lines)} LINES" if int(ignore_lines) > 0 else ""
    enclosed = f" ENCLOSED BY '{enclosed_by}'" if enclosed_by is not None and enclosed_by != "" else ""
    sql = (
        "LOAD DATA LOCAL INFILE '{file_path}' "
        "INTO TABLE {table} "
        "CHARACTER SET {charset} "
        "FIELDS TERMINATED BY '{ft}'{enclosed} ESCAPED BY '{eb}' "
        "LINES TERMINATED BY '{lt}'"
        "{ignore}"
        "{cols}"
        ";"
    ).format(
        file_path=fp,
        table=table,
        charset=charset,
        ft=fields_terminated_by,
        enclosed=enclosed,
        eb=escaped_by,
        lt=lines_terminated_by,
        ignore=ignore,
        cols=cols
    )
    return sql


def connect_mysql(host, port, user, password, database):
    conn = mysql.connector.connect(
        host=host,
        port=int(port),
        user=user,
        password=password,
        database=database,
        allow_local_infile=True,
        autocommit=False,
    )
    return conn


def enable_local_infile_session(cur):
    cur.execute("SET SESSION local_infile = 1")


def main():
    host = prompt("MySQL host", "127.0.0.1")
    port = prompt("MySQL port", "3306")
    user = prompt("MySQL user", "root")
    password = prompt("MySQL password", secret=True)
    database = prompt("MySQL database")

    table = prompt("Target table (e.g., schema.table or table)")
    fields_terminated_by = prompt("FIELDS TERMINATED BY", ",")
    enclosed_by = prompt("FIELDS ENCLOSED BY (blank for none)", '"')
    escaped_by = prompt("FIELDS ESCAPED BY", "\\")
    lines_terminated_by = prompt("LINES TERMINATED BY", "\\n")
    ignore_lines = prompt("IGNORE N LINES", "0")
    charset = prompt("CHARACTER SET", "utf8mb4")
    columns_csv = prompt("Optional column list CSV (e.g., col1,col2,...) (blank to omit)", "")

    paths_input = prompt("File path(s) (comma-separated)")
    if not paths_input:
        print("No file paths provided.", file=sys.stderr)
        sys.exit(2)

    file_paths = [p.strip() for p in paths_input.split(",") if p.strip()]
    if not file_paths:
        print("No valid file paths provided.", file=sys.stderr)
        sys.exit(2)

    for p in file_paths:
        if not os.path.exists(p):
            print(f"File not found: {p}", file=sys.stderr)
            sys.exit(2)

    try:
        conn = connect_mysql(host, port, user, password, database)
        cur = conn.cursor()
        enable_local_infile_session(cur)

        for file_path in file_paths:
            sql = build_load_sql(
                file_path=file_path,
                table=table,
                columns_csv=columns_csv if columns_csv else None,
                fields_terminated_by=fields_terminated_by,
                enclosed_by=enclosed_by if enclosed_by != "" else None,
                escaped_by=escaped_by,
                lines_terminated_by=lines_terminated_by.encode("utf-8").decode("unicode_escape"),
                ignore_lines=int(ignore_lines),
                charset=charset,
            )
            cur.execute(sql)
            conn.commit()
            print(f"Imported: {file_path}")

        cur.close()
        conn.close()

    except mysql.connector.Error as err:
        try:
            conn.rollback()
        except Exception:
            pass
        if err.errno == errorcode.ER_OPTION_PREVENTS_STATEMENT:
            print("MySQL server disallows LOCAL INFILE. Ensure local_infile=1 on server and allow_local_infile=True in connector.", file=sys.stderr)
        else:
            print(f"MySQL error: {err}", file=sys.stderr)
        sys.exit(1)
    except KeyboardInterrupt:
        try:
            conn.rollback()
        except Exception:
            pass
        print("Interrupted.", file=sys.stderr)
        sys.exit(130)


if __name__ == "__main__":
    main()